values
('f63578b7-705c-4e0b-a9e9-ecd5b5726b3f', null, 'category', 'Services', null, 'https://moodscale.in/#services', 0, true),
('51321bce-cb3b-417b-a7a3-4687fe86ce78', 'f63578b7-705c-4e0b-a9e9-ecd5b5726b3f', 'subcategory', 'Therapy Services', null, null, 0, true),
('41e6b2c9-58dd-45e5-a551-ef2ca44a2a6c', '51321bce-cb3b-417b-a7a3-4687fe86ce78', 'subcategory', 'Individual Therapy', null, 'https://moodscale.in/services/individual-therapy', 0, true),
('56879fcf-a58c-40c0-a1b4-d0ef2992079e', '41e6b2c9-58dd-45e5-a551-ef2ca44a2a6c', 'question', 'What is Individual Therapy?', 'Individual therapy is a collaborative process between you and a licensed mental health professional. It provides a safe, confidential space to explore thoughts, feelings, and behaviors while developing coping strategies.', 'https://moodscale.in/services/individual-therapy', 0, true),
('5acc362c-42f2-4810-aefb-08e6f7d960d4', '41e6b2c9-58dd-45e5-a551-ef2ca44a2a6c', 'question', 'What therapeutic approaches are used?', 'Our therapists use evidence-based techniques including CBT, DBT, and mindfulness-based interventions. Each treatment plan is customized to your unique concerns and goals.', 'https://moodscale.in/services/individual-therapy', 1, true),
('6f1e2d61-57ee-4532-ac48-f2504f907a88', '41e6b2c9-58dd-45e5-a551-ef2ca44a2a6c', 'question', 'Who can benefit from individual therapy?', 'Individual therapy can help with anxiety, depression, trauma, relationship issues, life transitions, stress management, and personal growth.', 'https://moodscale.in/services/individual-therapy', 2, true),
('e0e1eecc-c8b9-4350-a125-5061f359142a', '41e6b2c9-58dd-45e5-a551-ef2ca44a2a6c', 'question', 'What should I expect in sessions?', 'Your first session includes a comprehensive assessment. Regular sessions last 50 minutes, typically weekly or bi-weekly. Sessions are available online or in-person.', 'https://moodscale.in/services/individual-therapy', 3, true),
('06d675a7-c571-47d3-ac1e-d3ba205a261d', '41e6b2c9-58dd-45e5-a551-ef2ca44a2a6c', 'question', 'How much does individual therapy cost?', 'Individual therapy sessions start at ₹2,500 per session. Package deals for multiple sessions are available. Contact us to discuss payment plans.', 'https://moodscale.in/services/individual-therapy', 4, true),
('2dd674fe-50d0-4e25-aa95-6f679fc729f0', '51321bce-cb3b-417b-a7a3-4687fe86ce78', 'subcategory', 'Couples Therapy', null, 'https://moodscale.in/services/couples-therapy', 1, true),
('5c03ae44-9da3-4269-a8a5-c4664ceed5ea', '2dd674fe-50d0-4e25-aa95-6f679fc729f0', 'question', 'What is Couples Therapy?', 'Couples therapy helps partners improve their relationship through structured sessions. You learn to communicate effectively, resolve conflicts, and deepen emotional connection.', 'https://moodscale.in/services/couples-therapy', 0, true),
('978050d9-9fa2-4de9-a518-022a60074b6d', '2dd674fe-50d0-4e25-aa95-6f679fc729f0', 'question', 'What approaches do you use?', 'We use evidence-based methods including Emotionally Focused Therapy (EFT) and the Gottman Method in a neutral, supportive environment.', 'https://moodscale.in/services/couples-therapy', 1, true),
('dc8c5cde-aabd-4bb6-af8d-dc2b103bec87', '2dd674fe-50d0-4e25-aa95-6f679fc729f0', 'question', 'What issues can couples therapy address?', 'We help with communication difficulties, trust issues, intimacy concerns, conflict resolution, life transitions, parenting disagreements, and financial stress.', 'https://moodscale.in/services/couples-therapy', 2, true),
('630e380f-7c52-464e-a4c2-c11bdd97d942', '2dd674fe-50d0-4e25-aa95-6f679fc729f0', 'question', 'What should we expect in sessions?', 'Initial sessions explore your relationship history and goals. Sessions last 60–90 minutes with both partners. Progress is reviewed regularly.', 'https://moodscale.in/services/couples-therapy', 3, true),
('d58ea895-d867-4260-acec-5fa8bc799689', '2dd674fe-50d0-4e25-aa95-6f679fc729f0', 'question', 'How much does couples therapy cost?', 'Couples therapy sessions start at ₹3,500 per session. Package options and extended sessions are available. Same pricing applies for individuals and couples on platform plans.', 'https://moodscale.in/services/couples-therapy', 4, true),
('6e9b8136-7750-4a73-a00d-a6766a089746', '51321bce-cb3b-417b-a7a3-4687fe86ce78', 'subcategory', 'Group Therapy', null, 'https://moodscale.in/services/group-therapy', 2, true),
('394bdfae-e11f-4388-a3f2-5a55013fb872', '6e9b8136-7750-4a73-a00d-a6766a089746', 'question', 'What is Group Therapy?', 'Group therapy brings together individuals facing similar challenges with professional guidance. It provides peer support, diverse perspectives, and a safe, confidential environment.', 'https://moodscale.in/services/group-therapy', 0, true),
('2ec675cb-bc3d-4be7-a4e7-1d32152aa61d', '6e9b8136-7750-4a73-a00d-a6766a089746', 'question', 'What are the benefits of group therapy?', 'Benefits include reduced isolation, validation through shared experiences, learning from others'' coping strategies, and developing interpersonal skills.', 'https://moodscale.in/services/group-therapy', 1, true),
('21211421-228d-4b2c-aed8-e5ec73806991', '6e9b8136-7750-4a73-a00d-a6766a089746', 'question', 'What types of groups are offered?', 'Groups cover anxiety and depression support, grief and loss, addiction recovery, trauma healing, social skills development, and stress management.', 'https://moodscale.in/services/group-therapy', 2, true),
('9513c120-9a7b-4f30-ac03-5d9ec0346a92', '6e9b8136-7750-4a73-a00d-a6766a089746', 'question', 'How do groups work?', 'Groups have 6–10 members meeting weekly for 90-minute sessions. Facilitators lead structured discussions, exercises, and skill-building activities.', 'https://moodscale.in/services/group-therapy', 3, true),
('3ba15d99-0aa7-4d76-a74c-6c2f13c8677e', '6e9b8136-7750-4a73-a00d-a6766a089746', 'question', 'How much does group therapy cost?', 'Group therapy sessions are ₹1,500 per session. Most groups require a minimum 8-week commitment. Contact us for current group openings.', 'https://moodscale.in/services/group-therapy', 4, true),
('22247488-d024-46b7-af90-5332f5672454', '51321bce-cb3b-417b-a7a3-4687fe86ce78', 'subcategory', 'Psychological Consultation', null, 'https://moodscale.in/services/psychiatric-consultation', 3, true),
('203cc76a-d077-47a9-ac0e-3318652d5a87', '22247488-d024-46b7-af90-5332f5672454', 'question', 'What is Psychological Consultation?', 'Psychological consultation involves comprehensive evaluation by a licensed psychologist to assess and address mental health conditions using evidence-based interventions and testing.', 'https://moodscale.in/services/psychiatric-consultation', 0, true),
('3d06944a-bfe8-42b3-ab58-b1c0b3e4efd5', '22247488-d024-46b7-af90-5332f5672454', 'question', 'What services are provided?', 'Services include diagnostic evaluation, psychological testing, treatment planning, psychotherapy, and coordination with other healthcare providers.', 'https://moodscale.in/services/psychiatric-consultation', 1, true),
('1188f855-3a7e-4184-aec6-e1bd9bbe17d6', '22247488-d024-46b7-af90-5332f5672454', 'question', 'When should I seek psychological consultation?', 'Consider it for persistent mental health symptoms, psychological assessment needs, evidence-based therapy, or complex conditions requiring specialized expertise.', 'https://moodscale.in/services/psychiatric-consultation', 2, true),
('a7f79ea4-e53d-4236-af82-5653da332971', '22247488-d024-46b7-af90-5332f5672454', 'question', 'What happens in the initial consultation?', 'The first appointment lasts 60–90 minutes and includes evaluation, history review, symptom assessment, and initial treatment recommendations.', 'https://moodscale.in/services/psychiatric-consultation', 3, true),
('ff275f12-b4c5-48dd-a01b-6bbf252342e0', '22247488-d024-46b7-af90-5332f5672454', 'question', 'How much does psychological consultation cost?', 'Initial consultations are ₹3,500, with follow-up sessions at ₹2,000. Contact us to discuss payment options and package deals.', 'https://moodscale.in/services/psychiatric-consultation', 4, true),
('f1a8c376-273e-4f59-a363-689d35841d3f', '51321bce-cb3b-417b-a7a3-4687fe86ce78', 'subcategory', 'Corporate & Bulk Pricing', null, 'https://moodscale.in/services/custom-pricing', 4, true),
('3a1fa2ba-fbf4-44c6-a549-7f3c85ec1020', 'f1a8c376-273e-4f59-a363-689d35841d3f', 'question', 'What corporate programs does MoodScale offer?', 'We offer Employee Assistance Programs, executive wellness packages, team workshops, and bulk session packages tailored to organizations of all sizes.', 'https://moodscale.in/services/custom-pricing', 0, true),
('3f1d010b-d02a-465d-a732-0e678f406bf4', 'f1a8c376-273e-4f59-a363-689d35841d3f', 'question', 'What is included in the EAP?', 'EAP includes 24/7 crisis helpline access, unlimited email support, monthly wellness webinars, quarterly assessments, and dedicated therapist matching. Packages start from ₹500/employee/month for 50+ employees.', 'https://moodscale.in/services/custom-pricing', 1, true),
('403042ad-9e9f-4011-aa91-5dcce968b7fa', 'f1a8c376-273e-4f59-a363-689d35841d3f', 'question', 'What bulk pricing discounts are available?', 'Volume discounts: 20% off for 10–25 sessions, 30% for 26–50, 35% for 51–100, and up to 45% off for 100+ sessions with custom enterprise pricing.', 'https://moodscale.in/services/custom-pricing', 2, true),
('0da93896-81b2-457e-adc6-81edc107c9a4', 'f1a8c376-273e-4f59-a363-689d35841d3f', 'question', 'Do you offer team workshops?', 'Yes. Workshop topics include stress management, psychological safety, communication skills, workplace anxiety, and building mentally healthy teams for 10–500 participants.', 'https://moodscale.in/services/custom-pricing', 3, true),
('d1f4c9f0-2373-45b0-ad1f-ba6a62adfb0c', 'f1a8c376-273e-4f59-a363-689d35841d3f', 'question', 'How do I get a custom corporate quote?', 'Submit your organization details on our custom pricing page. Our team will contact you within 24 hours with a tailored proposal.', 'https://moodscale.in/services/custom-pricing', 4, true),
('84a2cf97-901f-4fd0-aedd-3926e933ee0f', 'f63578b7-705c-4e0b-a9e9-ecd5b5726b3f', 'subcategory', 'Features & Programs', null, null, 1, true),
('f34bacdd-d277-436e-ad1e-67d5ac55261c', '84a2cf97-901f-4fd0-aedd-3926e933ee0f', 'subcategory', 'Personal Growth & Development', null, 'https://moodscale.in/features/personal-growth', 0, true),
('bf2b6ea5-38d8-4bbb-a2a0-2e4b631b5303', 'f34bacdd-d277-436e-ad1e-67d5ac55261c', 'question', 'What is Personal Growth & Development?', 'Evidence-based personal development programs combining academic excellence, professional growth, and life skills mastery to help you achieve your goals.', 'https://moodscale.in/features/personal-growth', 0, true),
('52c3cb20-8f1b-4dd2-a3cd-877c3f77b366', 'f34bacdd-d277-436e-ad1e-67d5ac55261c', 'question', 'What is Goal Achievement Mastery?', 'A strategic goal-setting framework using SMART methodology, weekly accountability sessions, and a performance metrics dashboard to track progress.', 'https://moodscale.in/features/personal-growth', 1, true),
('e0713003-5a92-4ebe-a8d2-93143e1fc159', 'f34bacdd-d277-436e-ad1e-67d5ac55261c', 'question', 'What is the Academic Excellence Program?', 'Enhance learning with neuroscience-based study methods, memory optimization techniques, and focus enhancement training tailored to your learning style.', 'https://moodscale.in/features/personal-growth', 2, true),
('89adf70e-0064-44f6-a38b-fe8e167c6256', 'f34bacdd-d277-436e-ad1e-67d5ac55261c', 'question', 'What is Career Development & Leadership?', 'Accelerate professional growth with executive coaching, professional communication training, and strategic networking for career advancement.', 'https://moodscale.in/features/personal-growth', 3, true),
('4387baa0-7f04-4350-a494-695940c0f0ff', 'f34bacdd-d277-436e-ad1e-67d5ac55261c', 'question', 'How do I get started?', 'Begin with a free assessment or schedule a consultation to explore which personal development program fits your goals.', 'https://moodscale.in/features/personal-growth', 4, true),
('b474d554-04a3-42d0-a1a4-e0d949d9bfc7', '84a2cf97-901f-4fd0-aedd-3926e933ee0f', 'subcategory', 'Holistic Wellness Centers', null, 'https://moodscale.in/features/wellness-centers', 1, true),
('4c53cba6-0576-4834-ae5e-4d4bbc0e8614', 'b474d554-04a3-42d0-a1a4-e0d949d9bfc7', 'question', 'What are Holistic Wellness Centers?', 'State-of-the-art centers offering integrated programs combining traditional wisdom and modern therapeutic approaches for complete well-being.', 'https://moodscale.in/features/wellness-centers', 0, true),
('ac7e8d64-9423-4470-a46e-c3d75fd940de', 'b474d554-04a3-42d0-a1a4-e0d949d9bfc7', 'question', 'What is Yoga & Movement Therapy?', 'Therapeutic yoga, somatic movement, and breathwork sessions designed to release tension, build resilience, and restore inner balance.', 'https://moodscale.in/features/wellness-centers', 1, true),
('b867a3ba-c0ca-49ea-a4f2-4b0278e28efb', 'b474d554-04a3-42d0-a1a4-e0d949d9bfc7', 'question', 'What group programs are available?', 'Anxiety support groups, mindfulness circles, and peer support networks in a safe, facilitated environment.', 'https://moodscale.in/features/wellness-centers', 2, true),
('10f7a582-dedb-4959-aa30-3f4bdcd5cac7', 'b474d554-04a3-42d0-a1a4-e0d949d9bfc7', 'question', 'What integrative therapies are offered?', 'Art and music therapy, nutritional counseling, and biofeedback training for comprehensive mind-body wellness.', 'https://moodscale.in/features/wellness-centers', 3, true),
('ab60931a-142f-4cfe-a2dd-43a6dfe8f5cb', 'b474d554-04a3-42d0-a1a4-e0d949d9bfc7', 'question', 'How do I begin my wellness journey?', 'Visit our wellness centers page to explore programs and connect with our team to find the right program for you.', 'https://moodscale.in/features/wellness-centers', 4, true),
('9b1e192d-2575-4bad-aecb-d1444b3a2c0e', '84a2cf97-901f-4fd0-aedd-3926e933ee0f', 'subcategory', 'Nature Retreat Experience', null, 'https://moodscale.in/features/nature-retreat', 2, true),
('6fd01d00-41d0-4832-aeff-9986e72e076c', '9b1e192d-2575-4bad-aecb-d1444b3a2c0e', 'question', 'What is the Nature Retreat Experience?', 'Transformative nature retreats in carefully selected sanctuaries combining therapeutic benefits of natural environments with evidence-based mental wellness practices.', 'https://moodscale.in/features/nature-retreat', 0, true),
('9156e78f-5f50-4148-a82a-82166f20e137', '9b1e192d-2575-4bad-aecb-d1444b3a2c0e', 'question', 'What are Forest Therapy Sessions?', 'Guided forest meditation, sensory awareness walks, and nature connection rituals using scientifically-proven forest bathing techniques.', 'https://moodscale.in/features/nature-retreat', 1, true),
('6fa293da-baea-406d-a3ac-a0ea99ef8852', '9b1e192d-2575-4bad-aecb-d1444b3a2c0e', 'question', 'What are Mountain Meditation Retreats?', 'High-altitude retreats with silent meditation, sunrise yoga sessions, and peak mindfulness practices for clarity and renewal.', 'https://moodscale.in/features/nature-retreat', 2, true),
('4f6e2f25-b932-4fec-a15e-020d9dfaade9', '9b1e192d-2575-4bad-aecb-d1444b3a2c0e', 'question', 'What are Coastal Wellness Experiences?', 'Ocean sound therapy, beach meditation walks, and tidal breathing exercises harnessing the therapeutic power of marine environments.', 'https://moodscale.in/features/nature-retreat', 3, true),
('7c8cdf62-0214-4568-ac01-aadea21f7c53', '9b1e192d-2575-4bad-aecb-d1444b3a2c0e', 'question', 'How do I join a nature retreat?', 'Explore retreat programs on our Nature Retreat page and contact our team to learn about upcoming experiences.', 'https://moodscale.in/features/nature-retreat', 4, true),
('c889bd2e-8361-4761-a594-1e7f2ae97ea0', null, 'category', 'Find a Therapist', null, 'https://moodscale.in/therapists', 1, true),
('1352b29f-c3d6-4d87-acf8-7fb6e3f98327', 'c889bd2e-8361-4761-a594-1e7f2ae97ea0', 'question', 'Who are MoodScale therapists?', 'All therapists are licensed mental health professionals with extensive training. They hold relevant degrees in psychology, counseling, or related fields and are certified practitioners.', 'https://moodscale.in/therapists', 0, true),
('3bb53727-425d-4e81-a546-26113c0702d8', 'c889bd2e-8361-4761-a594-1e7f2ae97ea0', 'question', 'How do I browse therapists?', 'Visit our Therapists page to browse certified mental health professionals and find the expert who''s right for your journey.', 'https://moodscale.in/therapists', 1, true),
('65e31008-de9f-4baf-a860-b832902a784f', 'c889bd2e-8361-4761-a594-1e7f2ae97ea0', 'question', 'How does therapist matching work?', 'Our platform offers expert therapist matching based on your needs. After assessment, we help connect you with the right professional for your goals.', 'https://moodscale.in/therapists', 2, true),
('34b98455-34a6-48d9-a26b-6231a4068bf0', 'c889bd2e-8361-4761-a594-1e7f2ae97ea0', 'question', 'How do I book a session?', 'Book a session through our platform after browsing therapists. Flexible scheduling with online and in-person options is available.', 'https://moodscale.in/sessions/book-with-therapist', 3, true),
('a190f606-84a2-4443-a013-319a407a53f1', 'c889bd2e-8361-4761-a594-1e7f2ae97ea0', 'question', 'Are sessions online or in-person?', 'Therapy sessions are available both online and in-person based on your preference. All sessions are conducted in a confidential environment.', 'https://moodscale.in/therapists', 4, true),
('2bc5716e-dc7b-4271-aacf-e97955b0b759', 'c889bd2e-8361-4761-a594-1e7f2ae97ea0', 'question', 'What is the therapy journey on MoodScale?', 'Start with assessment, consult with a psychologist, begin therapy sessions, and receive ongoing support with progress tracking and 24/7 premium support.', 'https://moodscale.in/#work-process', 5, true),
('d0536129-99fb-46d6-a630-d4aeb987968b', null, 'category', 'Assessments', null, 'https://moodscale.in/assessments', 2, true),
('829d7415-54bd-40e2-a95a-4557d72cc96f', 'd0536129-99fb-46d6-a630-d4aeb987968b', 'subcategory', 'Personality', null, null, 0, true),
('446c3992-f4e4-4102-a343-139c0c5e6a0b', '829d7415-54bd-40e2-a95a-4557d72cc96f', 'question', 'What is the BFI-10 Personality Assessment?', 'A quick 10-item personality assessment based on the scientifically validated BFI-10 measuring the Big Five personality dimensions. Takes about 5 minutes.', 'https://moodscale.in/assessments', 0, true),
('36313c5b-0cab-4f54-aae6-294abbb7df6a', '829d7415-54bd-40e2-a95a-4557d72cc96f', 'question', 'What will I discover?', 'You''ll receive Big Five personality traits analysis, behavioral pattern understanding, and personal strengths identification using a validated tool.', 'https://moodscale.in/assessments', 1, true),
('3a624630-5436-4d61-ac49-bd62b7c9281b', '829d7415-54bd-40e2-a95a-4557d72cc96f', 'question', 'Is this assessment free?', 'Yes, the BFI-10 Big Five Personality Assessment is a free assessment available on MoodScale.', 'https://moodscale.in/assessments', 2, true),
('c6de3bdc-633b-41c4-a307-1354af52bba1', '829d7415-54bd-40e2-a95a-4557d72cc96f', 'question', 'How do I start the assessment?', 'Visit our Assessments page and select the BFI-10 assessment to begin. Answer carefully designed questions based on established psychological frameworks.', 'https://moodscale.in/assessments', 3, true),
('4bd982fd-0a94-45bd-af89-815c2238581a', 'd0536129-99fb-46d6-a630-d4aeb987968b', 'subcategory', 'Anxiety', null, null, 1, true),
('591f48cc-a7e9-461c-a61a-4d3b1b571419', '4bd982fd-0a94-45bd-af89-815c2238581a', 'question', 'What is the GAD-7 Anxiety Assessment?', 'A clinically validated 7-item screening tool for Generalized Anxiety Disorder based on DSM-IV criteria. Takes about 10 minutes.', 'https://moodscale.in/assessments', 0, true),
('26138598-c21a-4d1c-a65f-e74894203827', '4bd982fd-0a94-45bd-af89-815c2238581a', 'question', 'What will I discover?', 'You''ll receive a generalized anxiety assessment with quick, reliable results and professional interpretation guidance.', 'https://moodscale.in/assessments', 1, true),
('c40e8cc5-3967-43e5-ae4a-0d3abccc5141', '4bd982fd-0a94-45bd-af89-815c2238581a', 'question', 'Is this assessment free?', 'Yes, the GAD-7 Anxiety Assessment is a free screening tool available on MoodScale.', 'https://moodscale.in/assessments', 2, true),
('0a212410-c048-4e9c-a129-71a2077f5868', '4bd982fd-0a94-45bd-af89-815c2238581a', 'question', 'How do I start the assessment?', 'Go to our Assessments page and select GAD-7 to begin. Results help guide your therapy sessions and personal growth journey.', 'https://moodscale.in/assessments', 3, true),
('029e9dc3-0b16-424b-a21c-81acf7cc7fdd', 'd0536129-99fb-46d6-a630-d4aeb987968b', 'subcategory', 'ADHD', null, null, 2, true),
('a3109516-cba2-4482-adc8-e4edddb98c31', '029e9dc3-0b16-424b-a21c-81acf7cc7fdd', 'question', 'What is the ASRS-v1.1 ADHD Assessment?', 'A WHO-developed 18-item scale for screening adult ADHD symptoms based on DSM-IV criteria. Takes about 12 minutes.', 'https://moodscale.in/assessments', 0, true),
('41cc0c36-929d-42f5-a6ce-257ad44a4f78', '029e9dc3-0b16-424b-a21c-81acf7cc7fdd', 'question', 'What will I discover?', 'You''ll receive adult ADHD symptom evaluation, attention pattern analysis, and professional recommendations.', 'https://moodscale.in/assessments', 1, true),
('5b63785b-7020-45fc-a41a-9f54afdd098f', '029e9dc3-0b16-424b-a21c-81acf7cc7fdd', 'question', 'Is this a premium assessment?', 'Yes, the ASRS-v1.1 Adult ADHD Self-Report Scale is a premium assessment on MoodScale.', 'https://moodscale.in/assessments', 2, true),
('5e5a1039-3ee1-4a6b-a1d1-dd19232b4c7b', '029e9dc3-0b16-424b-a21c-81acf7cc7fdd', 'question', 'How do I start the assessment?', 'Visit our Assessments page and select the ASRS-v1.1 assessment to begin your screening.', 'https://moodscale.in/assessments', 3, true),
('95aabb2b-0273-495f-a008-19451e95f309', 'd0536129-99fb-46d6-a630-d4aeb987968b', 'subcategory', 'How Assessments Work', null, null, 3, true),
('e71e2c0e-3417-406f-a8e9-a226da75624c', '95aabb2b-0273-495f-a008-19451e95f309', 'question', 'How do MoodScale assessments work?', 'Take the assessment, receive a comprehensive report with insights, then use your results to guide therapy sessions and personal growth.', 'https://moodscale.in/assessments', 0, true),
('ef839b37-6ec4-49c9-a9c0-9dbb0574cce8', '95aabb2b-0273-495f-a008-19451e95f309', 'question', 'What is the difference between free and paid assessments?', 'MoodScale offers free basic assessments like BFI-10 and GAD-7, plus detailed paid evaluations including premium tools like ASRS-v1.1 for deeper insights.', 'https://moodscale.in/assessments', 1, true),
('0e50f14d-55c2-45fb-ae89-5f07cd9c8e24', '95aabb2b-0273-495f-a008-19451e95f309', 'question', 'Are assessments scientifically validated?', 'Yes. Our assessments are scientifically validated, HIPAA compliant, and used by 5000+ clients. They are designed by mental health professionals.', 'https://moodscale.in/assessments', 2, true),
('09d3c8c8-60df-47c5-a1fd-e9fed65b7523', '95aabb2b-0273-495f-a008-19451e95f309', 'question', 'Can I discuss results with a therapist?', 'Yes. Discuss your assessment results with certified psychologists to create a personalized treatment plan based on your mental health profile.', 'https://moodscale.in/assessments', 3, true),
('1e2b976c-300c-47a3-ae97-212893cc35ef', '95aabb2b-0273-495f-a008-19451e95f309', 'question', 'Where can I explore all assessments?', 'Visit our Assessments page to explore all available psychological assessments and start your discovery journey.', 'https://moodscale.in/assessments', 4, true),
('2c9f1700-7e73-4ced-a126-a826a9a37271', null, 'category', 'Pricing', null, 'https://moodscale.in/#contact', 3, true),
('0a0f9640-c281-4b05-aae7-4e6020b87143', '2c9f1700-7e73-4ced-a126-a826a9a37271', 'question', 'What is the Essential Care plan?', 'Essential Care is ₹1,199 per session (save 52% from ₹2,500). Includes one 50-minute session, expert therapist matching, 24/7 email support, and post-session guidance.', 'https://moodscale.in/#contact', 0, true),
('03c8d080-149d-4de0-a454-df3e0181c8ef', '2c9f1700-7e73-4ced-a126-a826a9a37271', 'question', 'What is the Premium Journey plan?', 'Premium Journey is ₹3,999 per package (save 67% from ₹12,000). Includes 4 sessions, 1 assessment session, a wellness report, personalised scheduling, and 24/7 priority support.', 'https://moodscale.in/#pricing', 1, true),
('364150d5-63c3-4b23-ae02-c65e77ea61bc', '2c9f1700-7e73-4ced-a126-a826a9a37271', 'question', 'What is the Transformative Care plan?', 'Transformative Care is ₹12,599 per program (save 50% from ₹25,000). Includes 12 sessions, 4 psychometric assessments, monthly and annual wellness reports, and 24/7 priority support.', 'https://moodscale.in/#pricing', 2, true),
('c06ca7fc-4852-48d6-ab77-9c5282ac2449', '2c9f1700-7e73-4ced-a126-a826a9a37271', 'question', 'Is pricing the same for individuals and couples?', 'Yes. All plans have the same price for individuals and couples. There are no hidden fees.', 'https://moodscale.in/#pricing', 3, true),
('b07800f3-f1f1-4015-ae6f-254db1aa0b0b', '2c9f1700-7e73-4ced-a126-a826a9a37271', 'question', 'Do you offer enterprise or bulk pricing?', 'Yes. We offer customized mental health programs including Employee Assistance Programs, executive wellness packages, and tailored workshops. Request a custom quote on our corporate pricing page.', 'https://moodscale.in/services/custom-pricing', 4, true),
('da401d67-83ec-4882-af4b-4d80e90f52fb', '2c9f1700-7e73-4ced-a126-a826a9a37271', 'question', 'How much do individual therapy sessions cost?', 'Standalone individual therapy sessions start at ₹2,500. Package plans on our pricing page offer significant savings. Couples sessions start at ₹3,500 and group sessions at ₹1,500.', 'https://moodscale.in/#pricing', 5, true),
('3cb3e3a1-edcf-4e83-a8e7-9f256d8c90a8', null, 'category', 'Support & FAQs', null, 'https://moodscale.in/faqs', 4, true),
('1f6194f1-9b53-424f-a2b6-dbedbbd479b5', '3cb3e3a1-edcf-4e83-a8e7-9f256d8c90a8', 'subcategory', 'General FAQs', null, null, 0, true),
('77f25e24-20dd-482f-a721-9e51272ee90b', '1f6194f1-9b53-424f-a2b6-dbedbbd479b5', 'question', 'What is MoodScale and how does it work?', 'MoodScale is a comprehensive mental health platform connecting individuals with licensed therapists and counselors. We offer personalized therapy sessions, mental health assessments, and wellness resources through convenient online sessions.', 'https://moodscale.in/faqs', 0, true),
('b9703e15-4459-4903-a37b-daeac8d3210c', '1f6194f1-9b53-424f-a2b6-dbedbbd479b5', 'question', 'Who are your therapists and counselors?', 'All therapists are licensed mental health professionals with extensive training and experience. They hold relevant degrees in psychology, counseling, or related fields.', 'https://moodscale.in/faqs', 1, true),
('c20748ef-9b20-409a-a128-ef83c840447f', '1f6194f1-9b53-424f-a2b6-dbedbbd479b5', 'question', 'How much do sessions cost?', 'Plans start at ₹1,199 per session (Essential Care). Premium Journey is ₹3,999 for 4 sessions and Transformative Care is ₹12,599 for 12 sessions. Individual sessions start at ₹2,500.', 'https://moodscale.in/faqs', 2, true),
('6b509406-0225-4721-a723-cf19021df149', '1f6194f1-9b53-424f-a2b6-dbedbbd479b5', 'question', 'Is my information secure and confidential?', 'Yes. Our platform is HIPAA-compliant and all communications are encrypted. Your personal information and session content are strictly confidential.', 'https://moodscale.in/faqs', 3, true),
('714c985b-eab7-4edb-ad4c-c9270ff7c464', '1f6194f1-9b53-424f-a2b6-dbedbbd479b5', 'question', 'What is MoodScale''s mission?', 'To provide evidence-based mental health assessments and resources that help individuals better understand and improve their mental wellbeing through accessible technology.', 'https://moodscale.in/about-us', 4, true),
('6b9cfa08-f82f-4429-acf3-6f85c95fdb8b', '3cb3e3a1-edcf-4e83-a8e7-9f256d8c90a8', 'subcategory', 'Support Options', null, 'https://moodscale.in/support-center', 1, true),
('60f7f313-6241-4f62-abc0-1f85bfd93770', '6b9cfa08-f82f-4429-acf3-6f85c95fdb8b', 'question', 'Is live chat support available?', 'Yes. Live chat support is available 24/7 with instant response from our support team.', 'https://moodscale.in/support-center', 0, true),
('878f6b7f-2ce0-4cb4-a2d4-99a4eacc6dbe', '6b9cfa08-f82f-4429-acf3-6f85c95fdb8b', 'question', 'Can I call for support?', 'Phone support is available Monday–Friday, 9:00 AM–8:00 PM. Call +91 9145607891 to speak with a representative.', 'https://moodscale.in/support-center', 1, true),
('bed6e04d-8a9d-47db-ab2a-cddac24c45a2', '6b9cfa08-f82f-4429-acf3-6f85c95fdb8b', 'question', 'How do I reach email support?', 'Email support is always open at contact@moodscale.in with responses within 24 hours.', 'https://moodscale.in/support-center', 2, true),
('0c74d8b2-200c-4446-a0f2-a5099784361e', '6b9cfa08-f82f-4429-acf3-6f85c95fdb8b', 'question', 'Where is the Support Center?', 'Visit our Support Center for live chat, phone, and email support options. Our team is committed to helping you every step of the way.', 'https://moodscale.in/support-center', 3, true),
('1ad9f9d7-a96d-47fa-a5d0-27cfe236c4f9', '3cb3e3a1-edcf-4e83-a8e7-9f256d8c90a8', 'subcategory', 'Important Notice', null, null, 2, true),
('fd816ab3-4899-4167-a4f6-5a63028ece96', '1ad9f9d7-a96d-47fa-a5d0-27cfe236c4f9', 'question', 'Is MoodScale a crisis helpline?', 'No. MoodScale is not a medical service or suicide prevention helpline. If you are in immediate distress, contact Tele MANAS: 1 800 891 4416 or AASRA: +91 22 2754 6669.', 'https://moodscale.in/faqs', 0, true),
('efd728b0-8921-4170-aa56-3475b09e3e52', '1ad9f9d7-a96d-47fa-a5d0-27cfe236c4f9', 'question', 'Where can I get immediate help?', 'For suicidal thoughts or immediate distress, contact a 24×7 suicide prevention helpline: Tele MANAS 1 800 891 4416 or AASRA +91 22 2754 6669.', 'https://moodscale.in/faqs', 1, true),
('5e5ccf3b-bdf4-4b34-af21-b065f36658ec', null, 'category', 'Contact Us', null, 'https://moodscale.in/#contact', 5, true),
('54725266-12dd-4932-a528-9d29843055a5', '5e5ccf3b-bdf4-4b34-af21-b065f36658ec', 'question', 'Where is MoodScale located?', 'Almasoul Consulting Private Limited, 7th floor, Icon Tower, Baner Road, Laxman Nagar, Baner, Pune, Maharashtra - 411045, India.', 'https://moodscale.in/#contact', 0, true),
('1b53fee4-da68-4d44-a7fb-fd88da6a3070', '5e5ccf3b-bdf4-4b34-af21-b065f36658ec', 'question', 'What is the contact phone number?', 'Call us at +91 9145607891 during office hours for assistance.', 'https://moodscale.in/#contact', 1, true),
('8dc0ed9a-cbb9-4553-a609-9493c8cdff30', '5e5ccf3b-bdf4-4b34-af21-b065f36658ec', 'question', 'What is the contact email?', 'Email us at contact@moodscale.in for inquiries. We respond within 24 hours.', 'https://moodscale.in/#contact', 2, true),
('f8a00695-1cc6-4c8f-ab30-5564b4f16f08', '5e5ccf3b-bdf4-4b34-af21-b065f36658ec', 'question', 'What are the office hours?', 'Monday–Friday: 9:00 AM–8:00 PM. Saturday: 10:00 AM–6:00 PM. Sunday: By appointment only.', 'https://moodscale.in/#contact', 3, true),
('2fe30502-d41c-4336-a446-ccc176f40af6', '5e5ccf3b-bdf4-4b34-af21-b065f36658ec',
